<?php if(!hasPermission('sales_create')){http_response_code(403); include __DIR__.'/../errors/403.php'; return;} $db=Database::connection(); $customers=$db->query('SELECT * FROM customers WHERE is_active=1')->fetchAll(); $errors=[]; if($_SERVER['REQUEST_METHOD']==='POST'){ $db->beginTransaction(); try{$cid=(int)$_POST['customer_id'];$date=$_POST['invoice_date'];$qty=(float)$_POST['qty'];$rate=(float)$_POST['rate'];$gstRate=(float)$_POST['gst_rate'];$ptype=$_POST['product_type'];$pid=(int)$_POST['product_id'];$line=$qty*$rate;$gst=$line*$gstRate/100;$total=$line+$gst; $c=$db->prepare('SELECT * FROM customers WHERE id=?');$c->execute([$cid]);$cust=$c->fetch(); if($cust['credit_limit']>0 && ($cust['opening_balance']+$total)>$cust['credit_limit']) throw new Exception('Credit limit exceeded'); $inv=generateInvoiceNo('SAL',getFinancialYear($date));$db->prepare("INSERT INTO sales_invoices (invoice_no,invoice_date,due_date,customer_id,sales_type,subtotal,taxable_amount,cgst_amount,sgst_amount,total_amount,paid_amount,balance_amount,payment_status,financial_year,created_by,created_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW())")->execute([$inv,$date,date('Y-m-d',strtotime($date.' +'.$cust['credit_period_days'].' days')),$cid,'credit',$line,$line,$gst/2,$gst/2,$total,0,$total,'pending',getFinancialYear($date),getCurrentUser()['id']??null]);$sid=$db->lastInsertId();$db->prepare('INSERT INTO sales_items (sales_id,product_type,rice_type_id,byproduct_id,packaging_type,quantity,rate_per_unit,gst_rate,gst_amount,total_amount) VALUES (?,?,?,?,?,?,?,?,?,?)')->execute([$sid,$ptype,$ptype==='rice'?$pid:null,$ptype==='byproduct'?$pid:null,'Loose',$qty,$rate,$gstRate,$gst,$total]);$db->prepare('UPDATE stock SET quantity_kg=quantity_kg-? WHERE product_type=? AND product_id=? LIMIT 1')->execute([$qty,$ptype,$pid]);$db->prepare("INSERT INTO stock_movements (product_type,product_id,packaging_type,warehouse_id,movement_type,reference_type,reference_id,quantity_kg,rate_per_kg,balance_quantity_kg,transaction_date,created_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?)")->execute([$ptype,$pid,'Loose',1,'out','sales',$sid,$qty,$rate,0,$date,getCurrentUser()['id']??null]);$v=generateInvoiceNo('VCH',getFinancialYear($date));$db->prepare('INSERT INTO vouchers (voucher_no,voucher_date,voucher_type,reference_table,reference_id,narration,total_debit,total_credit,financial_year,created_by,created_at) VALUES (?,?,?,?,?,?,?,?,?,?,NOW())')->execute([$v,$date,'receipt','sales_invoices',$sid,'Sales posting',$total,$total,getFinancialYear($date),getCurrentUser()['id']??null]);$vid=$db->lastInsertId();$ve=$db->prepare('INSERT INTO voucher_entries (voucher_id,account_id,debit_amount,credit_amount,party_type,party_id,narration) VALUES (?,?,?,?,?,?,?)');$ve->execute([$vid,3,$total,0,'customer',$cid,'Customer Dr']);$ve->execute([$vid,8,0,$line,'customer',$cid,'Sales Cr']);$ve->execute([$vid,6,0,$gst,'customer',$cid,'GST Cr']);$db->commit();redirect('sales/view/'.$sid);}catch(Throwable $e){$db->rollBack();$errors[]=$e->getMessage();}} ?>
<form method="post"><?php foreach($errors as $e) echo '<div>'.$e.'</div>'; ?><?=csrfField()?> <input type="date" name="invoice_date" value="<?=date('Y-m-d')?>"><select name="customer_id"><?php foreach($customers as $c):?><option value="<?=$c['id']?>"><?=sanitize($c['name'])?></option><?php endforeach;?></select><select name="product_type"><option value="rice">Rice</option><option value="byproduct">Byproduct</option></select><input name="product_id" placeholder="Product ID"><input name="qty" placeholder="Qty"><input name="rate" placeholder="Rate"><input name="gst_rate" value="5"><button>Save</button></form>
